mapper.delete:
DELETE FROM forest_scrap
WHERE forest_knot_id IN (
	SELECT id FROM forest_knot WHERE action_item_id IN (
		SELECT id FROM action_item WHERE entry_id = #{entryId}
	)
)

DELETE FROM forest_scrap
WHERE user_id = #{userId}
OR forest_knot_id IN (SELECT id FROM forest_knot WHERE user_id = #{userId})

mapper.select:
SELECT id, user_id, forest_knot_id, memo, created_at, updated_at
FROM forest_scrap
WHERE user_id = #{userId} AND forest_knot_id = #{forestKnotId}

SELECT fs.id, fs.user_id, fs.forest_knot_id, fs.memo, fs.created_at, fs.updated_at, fk.tag AS tag, fk.situation_summary AS situation_summary, fk.action_text AS action_text, fk.created_at AS knot_created_at, (SELECT COUNT(*) FROM forest_reaction fr WHERE fr.forest_knot_id = fk.id) AS reaction_count FROM forest_scrap fs JOIN forest_knot fk ON fk.id = fs.forest_knot_id WHERE fs.user_id = #{userId}
AND fk.tag = #{tag}
ORDER BY fs.created_at DESC
